args.sparql:
SELECT ?senator ?senatorLabel ?county ?countyLabel ?party ?partyLabel
WHERE {
  ?senator wdt:P39/wdt:P279 wd:Q1872510 .
  ?senator wdt:P768 ?county .
  ?county wdt:P17 wd:Q1014 .
  ?senator p:P39 ?statement .
  ?statement ps:P39 wd:Q1872510 ;
           pq:P4100 ?party .
  OPTIONAL { ?senator rdfs:label ?senatorLabel FILTER(LANG(?senatorLabel) = 'en') }
  OPTIONAL { ?county rdfs:label ?countyLabel FILTER(LANG(?countyLabel) = 'en') }
  OPTIONAL { ?party rdfs:label ?partyLabel FILTER(LANG(?partyLabel) = 'en') }
}
LIMIT 10

SELECT ?senator ?senatorLabel ?county ?countyLabel
WHERE {
  ?senator wdt:P39 wd:Q19885926 .
  ?senator p:P39 ?statement .
  ?statement ps:P39 wd:Q19885926 ;
             pq:P4100 wd:Q7307543 .
  ?senator wdt:P768 ?county .
  ?county wdt:P17 wd:Q1014 .
  OPTIONAL { ?senator rdfs:label ?senatorLabel FILTER(LANG(?senatorLabel) = 'en') }
  OPTIONAL { ?county rdfs:label ?countyLabel FILTER(LANG(?countyLabel) = 'en') }
}
ORDER BY ?senatorLabel
